checker_dsl:
EXISTS (`Variable V`) {
  AND {
    (`V's type is a ContainerType (CollectionType or MapType)`),
    OR {
      (`V is a LocalVariableDecl`),
      AND {
        (`V is a Field`),
        (`V is private`)
      }
    },
    NOT {
      OR {
        (`V is a DeserializableField`),
        (`V has an annotation that is a ReflectiveAccessAnnotation`),
        EXISTS (`XmlElement XE`) {
          AND {
            (`XE has an attribute whose value equals the fully qualified name of V's declaring type`),
            (`XE has an attribute whose value equals V's name`)
          }
        }
      }
    },
    FORALL (`VarAccess VA`) {
      OR {
        EXISTS (`AssignExpr AE`) {
          AND {
            (`VA is the destination of AE`),
            (`the source expression of AE is a FreshContainer (FreshCollection or FreshMap)`)
          }
        },
        AND {
          (`V is a LocalVariableDecl`),
          EXISTS (`ReturnStmt RS`) {
            (`VA is the expression of RS`)
          }
        },
        EXISTS (`MethodCall MA`) {
          AND {
            (`VA is the qualifier of MA`),
            (`the method of MA is a ContainerQueryMethod (CollectionQueryMethod or MapQueryMethod)`)
          }
        }
      }
    },
    EXISTS (`MethodCall MA2`) {
      AND {
        (`an access to V is the qualifier of MA2`),
        (`the method of MA2 is a ContainerQueryMethod (CollectionQueryMethod or MapQueryMethod)`)
      }
    },
    FORALL (`Expr E`) {
      (`E is a FreshContainer (FreshCollection or FreshMap)`)
    }
  }
}
